mapper.select:
select spm.id as rowId,spm.sys_no as sysNo,spi.name as projName,huser.name as applyName,spm.mid_date as midDate, spm.proj_id as projRowId,spm.proj_id as projId, spm.midcheck_state as midcheckState,spm.midcheck_opinion as midcheckOpinion, spm.midcheck_info_id as midcheckInfoRowId, spmi.midcheck_info as midcheckInfoName from srm_project_midcheck spm left join srm_projects_info spi on spi.id=spm.proj_id left join srm_project_midcheck_list_info spmi on spmi.id=spm.midcheck_info_id left join ct_srm_user huser on huser.id=spm.apply where 1=1
and spm.apply=#{projectMidcheckDto.userId}
and spm.proj_id=#{projectMidcheckDto.projId}
and spm.midcheck_state = #{projectMidcheckDto.midcheckState}
and spm.sys_no = #{projectMidcheckDto.sysNo}

select distinct spi.id as rowId,spi.sys_no as sysNo,spi.name as name,csy.name as yearName, huser.name as headName,sdept.name as deptName,spi.sub_no as subNo,suser.name as subUserName, spi.issued_date as issuedDate,spi.end_date as endDate,spi.acceptance_date as acceptanceDate, spi.proj_status as projStatus,spi.special_funds as specialFunds,spi.project_account as projectAccount, spi.enterprise_funds as enterpriseFunds,spi.data_status as dataStatus,spi.sub_date as subDate from srm_project_midcheck spm left join srm_projects_info spi on spi.id=spm.proj_id left join ct_srm_proj_type cspt on cspt.code=spi.proj_type left join ct_srm_year csy on csy.code=spi.year left join ct_srm_dept sdept on sdept.id=spi.dept_id left join ct_srm_user suser on suser.id=spi.sub_user_id left join ct_srm_user huser on huser.id=spi.head left join ct_srm_discipline fdiscipline on fdiscipline.code=spi.discipline left join ct_srm_person_type ccspt on ccspt.code=spi.head_type_code left join ct_srm_proj_level cspl on cspl.code=spi.proj_level left join srm_project_midcheck_list_info spmi on spmi.id=spm.midcheck_info_id left join ct_srm_user puser on puser.id=spm.apply left join cf_srm_eaf_rec eafrec on eafrec.sys_no=#{projectMidcheckDto.sysNo} and eafrec.check_rec_id=spm.id where spm.proj_id is not null and eafrec.step_no>1 and spi.sys_no=#{projectMidcheckDto.prjSysNo}
and ((spm.midcheck_state=1 and eafrec.is_current_step=1 and eafrec.checker_string LIKE CONCAT('%|', #{projectMidcheckDto.userId}, '|%')) or (eafrec.step_no = (select max(step_no) from cf_srm_eaf_rec seafrec where seafrec.sys_no=#{projectMidcheckDto.sysNo} and seafrec.check_rec_id=spm.id) and eafrec.checker_string LIKE CONCAT('%|', #{projectMidcheckDto.userId}, '|%') and eafrec.check_datetime is not null) or (spm.midcheck_state=0 and eafrec.is_current_step=1 and eafrec.check_result=3 and eafrec.checker_string LIKE CONCAT('%|', #{projectMidcheckDto.userId}, '|%')) )
and spm.midcheck_state=1 and eafrec.is_current_step=1 and eafrec.checker_string LIKE CONCAT('%|', #{projectMidcheckDto.userId}, '|%')
and spm.midcheck_state=1 and eafrec.check_result="2" and eafrec.checker_string LIKE CONCAT('%|', #{projectMidcheckDto.userId}, '|%')
and spm.midcheck_state=0 and eafrec.check_result="3" and eafrec.checker_string LIKE CONCAT('%|', #{projectMidcheckDto.userId}, '|%')
and spi.name LIKE CONCAT('%', #{projectMidcheckDto.projName}, '%')
and spi.proj_type = #{projectMidcheckDto.projType}
and spi.head = #{projectMidcheckDto.projHead}
